def parse_duration(s: str) -> int:
    """
    Parse a duration string and return the number of seconds.

    Args:
        s: Duration string in format like '2h30m', '45m', '1h', '90s'

    Returns:
        Number of seconds

    Raises:
        ValueError: If the input is invalid
    """
    if not isinstance(s, str) or not s:
        raise ValueError("Invalid input: expected non-empty string")

    total_seconds = 0
    current_num = ""

    for char in s:
        if char.isdigit():
            current_num += char
        elif char in 'hms':
            if not current_num:
                raise ValueError(f"Invalid input: missing number before '{char}'")
            value = int(current_num)
            current_num = ""

            if char == 'h':
                total_seconds += value * 3600
            elif char == 'm':
                total_seconds += value * 60
            elif char == 's':
                total_seconds += value
        else:
            raise ValueError(f"Invalid input: unrecognized character '{char}'")

    if current_num:
        raise ValueError("Invalid input: missing unit at the end")

    if total_seconds == 0 and s != '0s':
        raise ValueError("Invalid input: no valid duration found")

    return total_seconds
